sql:
SELECT app_id, rating_value
FROM app_ratings
ORDER BY rating_value DESC;

external_knowledge:
- 'Prolific critics' refers to users who have written more than one approved review for applications they have downloaded; 
- 'Body of work' refers to the total number of approved reviews written by a user; 
- 'Average praise level' refers to the average rating given by a user across all their approved reviews.

sql:
SELECT app_id, rating_value
FROM app_ratings
WHERE rating_value > 4.0;

SELECT app_id, AVG(rating_value) AS average_rating
FROM app_ratings
GROUP BY app_id;

SELECT download_device_type, COUNT(*) AS download_count
FROM app_downloads
GROUP BY download_device_type;

SELECT version_description
FROM app_versions
WHERE app_id = 1;
